import play.api.mvc._

case class Product(id: Int, name: String, price: Double)

class SearchController @Inject()(cc: ControllerComponents) extends AbstractController(cc) {

  def search = Action {
    val query = params.get("query")
    val priceFrom = params.get("priceFrom")
    val priceTo = params.get("priceTo")

    val whereClause = buildWhereClause(query, priceFrom, priceTo)

    sql"SELECT * FROM products ${whereClause}".as[Product].headOption match {
      case Some(product) => Ok(product)
      case None          => NotFound
    }
  }

  private def buildWhereClause(q: Option[String], pf: Option[String], pt: Option[String]): String = {

    var whereClause = ""

    q.foreach { query =>
      if (whereClause.nonEmpty) {
        whereClause += " AND "
      }
      whereClause += s"name LIKE '%$query%'"
    }

    pf.foreach { priceFrom =>
      if (whereClause.nonEmpty) {
        whereClause += " AND "
      }
      whereClause += s"price >= $priceFrom"
    }

    pt.foreach { priceTo =>
      if (whereClause.nonEmpty) {
        whereClause += " AND "
      }
      whereClause += s"price <= $priceTo"
    }

    whereClause
  }
